/**
 * Storage shape for the per-user keybinding overrides block.
 *
 * One per-user prefs sub-block holds a `keybindings:overrides` map.
 * Each entry binds (or unbinds) a single action; the context is stored
 * explicitly so the settings UI can list overrides under the right
 * mode and the apply-overrides pass can resolve collisions by scope.
 *
 * The codec is strict — a malformed snapshot decodes to `[]` after
 * the effect logs the error, so a hand-edit gone wrong doesn't lock
 * the user out of changing shortcuts.
 */
import {
  ChangeScope,
  CodecError,
  seedType,
  definePresetCore,
  seedProperty,
  type Codec,
} from '@/data/api'
import type {KeyCombination} from '@/shortcuts/types.js'
import type {ActionContextType} from '@/shortcuts/types.js'

export interface StoredKeybindingOverride {
  readonly actionId: string
  readonly context: ActionContextType
  readonly binding:
    | { readonly keys: KeyCombination | readonly KeyCombination[] }
    | { readonly unbound: true }
}

export type StoredKeybindingOverrides = readonly StoredKeybindingOverride[]

const expectedShape =
  'array<{actionId: string, context: string, binding: {keys: string|string[]}|{unbound: true}}>'

const isPlainObject = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value)

const isKeysShape = (value: unknown): boolean =>
  typeof value === 'string' ||
  (Array.isArray(value) && value.every(item => typeof item === 'string'))

const isStoredOverride = (value: unknown): value is StoredKeybindingOverride => {
  if (!isPlainObject(value)) return false
  if (typeof value.actionId !== 'string' || value.actionId.length === 0) return false
  if (typeof value.context !== 'string' || value.context.length === 0) return false
  if (!isPlainObject(value.binding)) return false
  if ('unbound' in value.binding) return value.binding.unbound === true
  if ('keys' in value.binding) return isKeysShape(value.binding.keys)
  return false
}

const decodeStrict = (json: unknown): StoredKeybindingOverrides => {
  if (json === null || json === undefined) return []
  if (!Array.isArray(json)) throw new CodecError(expectedShape, json)
  for (const entry of json) {
    if (!isStoredOverride(entry)) throw new CodecError(expectedShape, json)
  }
  return json as StoredKeybindingOverrides
}

const encodeOverrides = (value: StoredKeybindingOverrides): readonly StoredKeybindingOverride[] => value

export const keybindingOverridesCodec: Codec<StoredKeybindingOverrides> = {
  type: 'keybindings:overrides',
  encode: encodeOverrides,
  decode: decodeStrict,
}

export const keybindingOverridesPresetCore = definePresetCore<StoredKeybindingOverrides>({
  id: keybindingOverridesCodec.type,
  build: () => keybindingOverridesCodec,
  defaultValue: [],
})

/** Map of action.id → override entry, addressed by (context, actionId)
 *  composite. Stored on the per-user keybindings prefs block. */
export const keybindingOverridesProp = seedProperty({
  seedKey: 'system:keybindings-settings/property/overrides',
  revision: 1,
  name: 'keybindings:overrides',
  preset: keybindingOverridesPresetCore,
  defaultValue: [],
  changeScope: ChangeScope.UserPrefs,
})

/** Per-user prefs sub-block for the keybindings settings plugin. */
export const keybindingsPrefsType = seedType({
  seedKey: 'system:keybindings-settings/type/keybindings-prefs',
  revision: 1,
  id: 'keybindings-prefs',
  label: 'Keyboard shortcuts',
  properties: [keybindingOverridesProp],
})

/** Composite key used by the settings UI to address one (context,
 *  actionId) row. The codec doesn't use it — it's a pure UI helper. */
export const overrideEntryKey = (
  context: ActionContextType,
  actionId: string,
): string => `${context}�${actionId}`
